  1→/**
  2→ * React component for displaying most common vulnerabilities table
  3→ *
  4→ * Displays top 10 vulnerabilities ranked by occurrence frequency.
  5→ * Features:
  6→ * - Bootstrap table with responsive design
  7→ * - Severity badges with color coding (CRITICAL=red, HIGH=orange, MEDIUM=yellow, LOW=blue, UNKNOWN=gray)
  8→ * - Click handlers for drill-down navigation to vulnerability details
  9→ * - Loading, error, and empty states
 10→ *
 11→ * Feature: 036-vuln-stats-lense
 12→ * Task: T016 [US1]
 13→ * Spec reference: spec.md FR-001, FR-002
 14→ * User Story: US1 - View Most Common Vulnerabilities (P1/MVP)
 15→ */
 16→
 17→import React, { useEffect, useState } from 'react';
 18→import ExcelJS from 'exceljs';
 19→import { vulnerabilityStatisticsApi, type MostCommonVulnerabilityDto, type AffectedAssetsByCveDto } from '../../services/api/vulnerabilityStatisticsApi';
 20→import CveLink from '../CveLink';
 21→
 22→/**
 23→ * Map severity levels to Scandinavian design system badge classes
 24→ */
 25→const severityBadgeClass = (severity: string): string => {
 26→  switch (severity.toUpperCase()) {
 27→    case 'CRITICAL':
 28→      return 'badge scand-critical';
 29→    case 'HIGH':
 30→      return 'badge scand-high';
 31→    case 'MEDIUM':
 32→      return 'badge scand-medium';
 33→    case 'LOW':
 34→      return 'badge scand-low';
 35→    case 'UNKNOWN':
 36→    default:
 37→      return 'badge scand-neutral';
 38→  }
 39→};
 40→
 41→/**
 42→ * Props for MostCommonVulnerabilities component
 43→ *
 44→ * Feature: 059-vuln-stats-domain-filter
 45→ * Task: T012 [US1]
 46→ */
 47→interface MostCommonVulnerabilitiesProps {
 48→  /** Optional AD domain filter (null = all domains) */
 49→  domain?: string | null;
 50→  /** Optional AWS hosted filter (true = only cloud-hosted assets) */
 51→  awsHosted?: boolean;
 52→}
 53→
 54→export default function MostCommonVulnerabilities({ domain, awsHosted }: MostCommonVulnerabilitiesProps = {}) {
 55→  const [data, setData] = useState<MostCommonVulnerabilityDto[]>([]);
 56→  const [loading, setLoading] = useState<boolean>(true);
 57→  const [error, setError] = useState<string | null>(null);
 58→
 59→  // Modal state for CVE drilldown
 60→  const [showModal, setShowModal] = useState<boolean>(false);
 61→  const [modalLoading, setModalLoading] = useState<boolean>(false);
 62→  const [modalData, setModalData] = useState<AffectedAssetsByCveDto | null>(null);
 63→  const [modalError, setModalError] = useState<string | null>(null);
 64→
 65→  /**
 66→   * Handle row click - show affected systems modal
 67→   */
 68→  const handleRowClick = async (cveId: string) => {
 69→    setShowModal(true);
 70→    setModalLoading(true);
 71→    setModalError(null);
 72→    setModalData(null);
 73→
 74→    try {
 75→      const result = await vulnerabilityStatisticsApi.getAffectedAssetsByCve(cveId, domain, awsHosted);
 76→      setModalData(result);
 77→    } catch (err) {
 78→      console.error('Error fetching affected assets:', err);
 79→      setModalError('Failed to load affected systems. Please try again.');
 80→    } finally {
 81→      setModalLoading(false);
 82→    }
 83→  };
 84→
 85→  const closeModal = () => {
 86→    setShowModal(false);
 87→    setModalData(null);
 88→    setModalError(null);
 89→  };
 90→
 91→  // Export state
 92→  const [exporting, setExporting] = useState<boolean>(false);
 93→
 94→  /**
 95→   * Export affected systems to Excel
 96→   */
 97→  const handleExportAffectedSystems = async () => {
 98→    if (!modalData || modalData.affectedAssets.length === 0) return;
 99→
100→    setExporting(true);
101→    try {
102→      const workbook = new ExcelJS.Workbook();
103→      workbook.creator = 'Secman';
104→      workbook.created = new Date();
105→
106→      const sheet = workbook.addWorksheet('Affected Systems');
107→      sheet.columns = [
108→        { header: 'System Name', key: 'name', width: 30 },
109→        { header: 'IP Address', key: 'ip', width: 18 },
110→        { header: 'Domain', key: 'domain', width: 20 },
111→        { header: 'Type', key: 'type', width: 15 },
112→      ];
113→
114→      modalData.affectedAssets.forEach((asset) => {
115→        sheet.addRow({
116→          name: asset.assetName,
117→          ip: asset.assetIp || '-',
118→          domain: asset.adDomain || '-',
119→          type: asset.assetType || '-',
120→        });
121→      });
122→
123→      // Style header
124→      const headerRow = sheet.getRow(1);
125→      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
126→      headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF3D4F4F' } };
127→      headerRow.height = 22;
128→
129→      // Generate and download
130→      const buffer = await workbook.xlsx.writeBuffer();
131→      const blob = new Blob([buffer], {
132→        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
133→      });
134→
135→      const safeCveId = modalData.cveId.replace(/[^a-zA-Z0-9-]/g, '_');
136→      const dateStr = new Date().toISOString().split('T')[0];
137→      const url = window.URL.createObjectURL(blob);
138→      const link = document.createElement('a');
139→      link.href = url;
140→      link.download = `Affected_Systems_${safeCveId}_${dateStr}.xlsx`;
141→      document.body.appendChild(link);
142→      link.click();
143→      document.body.removeChild(link);
144→      window.URL.revokeObjectURL(url);
145→    } catch (err) {
146→      console.error('Export failed:', err);
147→    } finally {
148→      setExporting(false);
149→    }
150→  };
151→
152→  useEffect(() => {
153→    const fetchData = async () => {
154→      try {
155→        setLoading(true);
156→        setError(null);
157→        const result = await vulnerabilityStatisticsApi.getMostCommonVulnerabilities(domain, awsHosted);
158→        setData(result);
159→      } catch (err) {
160→        console.error('Error fetching most common vulnerabilities:', err);
161→        setError('Failed to load vulnerability statistics. Please try again later.');
162→      } finally {
163→        setLoading(false);
164→      }
165→    };
166→
167→    fetchData();
168→  }, [domain, awsHosted]); // Re-fetch when domain or awsHosted changes
169→
170→  // Loading state
171→  if (loading) {
172→    return (
173→      <div className="card">
174→        <div className="card-body text-center py-5">
175→          <div className="spinner-border text-primary" role="status">
176→            <span className="visually-hidden">Loading...</span>
177→          </div>
178→          <p className="mt-3 text-muted">Loading vulnerability statistics...</p>
179→        </div>
180→      </div>
181→    );
182→  }
183→
184→  // Error state
185→  if (error) {
186→    return (
187→      <div className="card">
188→        <div className="card-body">
189→          <div className="alert alert-danger" role="alert">
190→            <i className="bi bi-exclamation-triangle me-2"></i>
191→            {error}
192→          </div>
193→        </div>
194→      </div>
195→    );
196→  }
197→
198→  // Empty state
199→  if (data.length === 0) {
200→    return (
201→      <div className="card">
202→        <div className="card-body text-center py-5">
203→          <i className="bi bi-inbox display-4 text-muted"></i>
204→          <p className="mt-3 text-muted">No vulnerability data available.</p>
205→          <small className="text-muted">
206→            This could mean no vulnerabilities have been imported yet, or you don't have access to any workgroups with vulnerabilities.
207→          </small>
208→        </div>
209→      </div>
210→    );
211→  }
212→
213→  // Data table
214→  return (
215→    <div className="card">
216→      <div className="card-header" style={{backgroundColor: 'var(--scand-bg-header)', color: 'var(--scand-text-light)'}}>
217→        <h5 className="mb-0">
218→          <i className="bi bi-shield-exclamation me-2"></i>
219→          Top 10 Most Common Vulnerabilities
220→        </h5>
221→      </div>
222→      <div className="card-body p-0">
223→        <div className="table-responsive">
224→          <table className="table table-hover mb-0">
225→            <thead className="table-light">
226→              <tr>
227→                <th scope="col">#</th>
228→                <th scope="col">CVE ID</th>
229→                <th scope="col">Severity</th>
230→                <th scope="col">Total Occurrences</th>
231→                <th scope="col">Affected Assets</th>
232→              </tr>
233→            </thead>
234→            <tbody>
235→              {data.map((vuln, index) => (
236→                <tr
237→                  key={`${vuln.vulnerabilityId}-${vuln.cvssSeverity}`}
238→                  onClick={() => handleRowClick(vuln.vulnerabilityId)}
239→                  style={{ cursor: 'pointer' }}
240→                  title={`Click to view details for ${vuln.vulnerabilityId}`}
241→                >
242→                  <td className="align-middle">{index + 1}</td>
243→                  <td className="align-middle">
244→                    <CveLink cveId={vuln.vulnerabilityId} />
245→                  </td>
246→                  <td className="align-middle">
247→                    <span className={severityBadgeClass(vuln.cvssSeverity)}>
248→                      {vuln.cvssSeverity}
249→                    </span>
250→                  </td>
251→                  <td className="align-middle">
252→                    <span className="badge bg-light text-dark">
253→                      {vuln.occurrenceCount.toLocaleString()}
254→                    </span>
255→                  </td>
256→                  <td className="align-middle">
257→                    <span className="badge bg-light text-dark">
258→                      {vuln.affectedAssetCount.toLocaleString()}
259→                    </span>
260→                  </td>
261→                </tr>
262→              ))}
263→            </tbody>
264→          </table>
265→        </div>
266→      </div>
267→      <div className="card-footer text-muted small">
268→        <i className="bi bi-info-circle me-1"></i>
269→        Showing top 10 vulnerabilities ranked by total occurrences. Click any row for details.
270→      </div>
271→
272→      {/* CVE Affected Systems Modal */}
273→      {showModal && (
274→        <div className="modal show d-block" tabIndex={-1} style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
275→          <div className="modal-dialog modal-lg modal-dialog-scrollable">
276→            <div className="modal-content">
277→              <div className="modal-header" style={{ backgroundColor: 'var(--scand-bg-header)', color: 'var(--scand-text-light)' }}>
278→                <h5 className="modal-title">
279→                  <i className="bi bi-server me-2"></i>
280→                  Affected Systems {modalData && `- ${modalData.cveId}`}
281→                </h5>
282→                <button type="button" className="btn-close btn-close-white" onClick={closeModal}></button>
283→              </div>
284→              <div className="modal-body">
285→                {modalLoading && (
286→                  <div className="text-center py-4">
287→                    <div className="spinner-border text-primary" role="status">
288→                      <span className="visually-hidden">Loading...</span>
289→                    </div>
290→                    <p className="mt-2 text-muted">Loading affected systems...</p>
291→                  </div>
292→                )}
293→
294→                {modalError && (
295→                  <div className="alert alert-danger" role="alert">
296→                    <i className="bi bi-exclamation-triangle me-2"></i>
297→                    {modalError}
298→                  </div>
299→                )}
300→
301→                {modalData && !modalLoading && (
302→                  <>
303→                    <div className="mb-3">
304→                      <span className={severityBadgeClass(modalData.severity)}>{modalData.severity}</span>
305→                      <span className="ms-2 text-muted">
306→                        {modalData.totalCount} system{modalData.totalCount !== 1 ? 's' : ''} affected
307→                        {domain && <span className="ms-1">(in domain: {domain})</span>}
308→                      </span>
309→                    </div>
310→
311→                    {modalData.affectedAssets.length === 0 ? (
312→                      <p className="text-muted">No systems found for this vulnerability in your accessible scope.</p>
313→                    ) : (
314→                      <div className="table-responsive">
315→                        <table className="table table-sm table-hover mb-0">
316→                          <thead className="table-light">
317→                            <tr>
318→                              <th>System Name</th>
319→                              <th>IP Address</th>
320→                              <th>Domain</th>
321→                              <th>Type</th>
322→                            </tr>
323→                          </thead>
324→                          <tbody>
325→                            {modalData.affectedAssets.map((asset) => (
326→                              <tr key={asset.assetId}>
327→                                <td>
328→                                  <a href={`/assets/${asset.assetId}`} className="text-decoration-none">
329→                                    {asset.assetName}
330→                                  </a>
331→                                </td>
332→                                <td>{asset.assetIp || '-'}</td>
333→                                <td>{asset.adDomain || '-'}</td>
334→                                <td>{asset.assetType || '-'}</td>
335→                              </tr>
336→                            ))}
337→                          </tbody>
338→                        </table>
339→                      </div>
340→                    )}
341→
342→                    {modalData.totalCount >= 100 && (
343→                      <div className="alert alert-info mt-3 mb-0" role="alert">
344→                        <i className="bi bi-info-circle me-2"></i>
345→                        Showing first 100 affected systems. Use the asset overview for a complete list.
346→                      </div>
347→                    )}
348→                  </>
349→                )}
350→              </div>
351→              <div className="modal-footer">
352→                {modalData && modalData.affectedAssets.length > 0 && (
353→                  <button
354→                    type="button"
355→                    className="btn btn-outline-success me-auto"
356→                    onClick={handleExportAffectedSystems}
357→                    disabled={exporting}
358→                  >
359→                    {exporting ? (
360→                      <>
361→                        <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
362→                        Exporting...
363→                      </>
364→                    ) : (
365→                      <>
366→                        <i className="bi bi-file-earmark-excel me-2"></i>
367→                        Export to Excel
368→                      </>
369→                    )}
370→                  </button>
371→                )}
372→                <button type="button" className="btn btn-secondary" onClick={closeModal}>Close</button>
373→              </div>
374→            </div>
375→          </div>
