/**
 * React component for displaying most common vulnerabilities table
 *
 * Displays top 10 vulnerabilities ranked by occurrence frequency.
 * Features:
 * - Bootstrap table with responsive design
 * - Severity badges with color coding (CRITICAL=red, HIGH=orange, MEDIUM=yellow, LOW=blue, UNKNOWN=gray)
 * - Click handlers for drill-down navigation to vulnerability details
 * - Loading, error, and empty states
 *
 * Feature: 036-vuln-stats-lense
 * Task: T016 [US1]
 * Spec reference: spec.md FR-001, FR-002
 * User Story: US1 - View Most Common Vulnerabilities (P1/MVP)
 */

import React, { useEffect, useState } from 'react';
import ExcelJS from 'exceljs';
import { vulnerabilityStatisticsApi, type MostCommonVulnerabilityDto, type AffectedAssetsByCveDto } from '../../services/api/vulnerabilityStatisticsApi';
import CveLink from '../CveLink';

/**
 * Map severity levels to Scandinavian design system badge classes
 */
const severityBadgeClass = (severity: string): string => {
  switch (severity.toUpperCase()) {
    case 'CRITICAL':
      return 'badge scand-critical';
    case 'HIGH':
      return 'badge scand-high';
    case 'MEDIUM':
      return 'badge scand-medium';
    case 'LOW':
      return 'badge scand-low';
    case 'UNKNOWN':
    default:
      return 'badge scand-neutral';
  }
};

/**
 * Props for MostCommonVulnerabilities component
 *
 * Feature: 059-vuln-stats-domain-filter
 * Task: T012 [US1]
 */
interface MostCommonVulnerabilitiesProps {
  /** Optional AD domain filter (null = all domains) */
  domain?: string | null;
  /** Optional AWS hosted filter (true = only cloud-hosted assets) */
  awsHosted?: boolean;
}

export default function MostCommonVulnerabilities({ domain, awsHosted }: MostCommonVulnerabilitiesProps = {}) {
  const [data, setData] = useState<MostCommonVulnerabilityDto[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Modal state for CVE drilldown
  const [showModal, setShowModal] = useState<boolean>(false);
  const [modalLoading, setModalLoading] = useState<boolean>(false);
  const [modalData, setModalData] = useState<AffectedAssetsByCveDto | null>(null);
  const [modalError, setModalError] = useState<string | null>(null);

  /**
   * Handle row click - show affected systems modal
   */
  const handleRowClick = async (cveId: string) => {
    setShowModal(true);
    setModalLoading(true);
    setModalError(null);
    setModalData(null);

    try {
      const result = await vulnerabilityStatisticsApi.getAffectedAssetsByCve(cveId, domain, awsHosted);
      setModalData(result);
    } catch (err) {
      console.error('Error fetching affected assets:', err);
      setModalError('Failed to load affected systems. Please try again.');
    } finally {
      setModalLoading(false);
    }
  };

  const closeModal = () => {
    setShowModal(false);
    setModalData(null);
    setModalError(null);
  };

  // Export state
  const [exporting, setExporting] = useState<boolean>(false);

  /**
   * Export affected systems to Excel
   */
  const handleExportAffectedSystems = async () => {
    if (!modalData || modalData.affectedAssets.length === 0) return;

    setExporting(true);
    try {
      const workbook = new ExcelJS.Workbook();
      workbook.creator = 'Secman';
      workbook.created = new Date();

      const sheet = workbook.addWorksheet('Affected Systems');
      sheet.columns = [
        { header: 'System Name', key: 'name', width: 30 },
        { header: 'IP Address', key: 'ip', width: 18 },
        { header: 'Domain', key: 'domain', width: 20 },
        { header: 'Type', key: 'type', width: 15 },
      ];

      modalData.affectedAssets.forEach((asset) => {
        sheet.addRow({
          name: asset.assetName,
          ip: asset.assetIp || '-',
          domain: asset.adDomain || '-',
          type: asset.assetType || '-',
        });
      });

      // Style header
      const headerRow = sheet.getRow(1);
      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
      headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF3D4F4F' } };
      headerRow.height = 22;

      // Generate and download
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
      });

      const safeCveId = modalData.cveId.replace(/[^a-zA-Z0-9-]/g, '_');
      const dateStr = new Date().toISOString().split('T')[0];
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `Affected_Systems_${safeCveId}_${dateStr}.xlsx`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error('Export failed:', err);
    } finally {
      setExporting(false);
    }
  };

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);
        const result = await vulnerabilityStatisticsApi.getMostCommonVulnerabilities(domain, awsHosted);
        setData(result);
      } catch (err) {
        console.error('Error fetching most common vulnerabilities:', err);
        setError('Failed to load vulnerability statistics. Please try again later.');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [domain, awsHosted]); // Re-fetch when domain or awsHosted changes

  // Loading state
  if (loading) {
    return (
      <div className="card">
        <div className="card-body text-center py-5">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
          <p className="mt-3 text-muted">Loading vulnerability statistics...</p>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="card">
        <div className="card-body">
          <div className="alert alert-danger" role="alert">
            <i className="bi bi-exclamation-triangle me-2"></i>
            {error}
          </div>
        </div>
      </div>
    );
  }

  // Empty state
  if (data.length === 0) {
    return (
      <div className="card">
        <div className="card-body text-center py-5">
          <i className="bi bi-inbox display-4 text-muted"></i>
          <p className="mt-3 text-muted">No vulnerability data available.</p>
          <small className="text-muted">
            This could mean no vulnerabilities have been imported yet, or you don't have access to any workgroups with vulnerabilities.
          </small>
        </div>
      </div>
    );
  }

  // Data table
  return (
    <div className="card">
      <div className="card-header" style={{backgroundColor: 'var(--scand-bg-header)', color: 'var(--scand-text-light)'}}>
        <h5 className="mb-0">
          <i className="bi bi-shield-exclamation me-2"></i>
          Top 10 Most Common Vulnerabilities
        </h5>
      </div>
      <div className="card-body p-0">
        <div className="table-responsive">
          <table className="table table-hover mb-0">
            <thead className="table-light">
              <tr>
                <th scope="col">#</th>
                <th scope="col">CVE ID</th>
                <th scope="col">Severity</th>
                <th scope="col">Total Occurrences</th>
                <th scope="col">Affected Assets</th>
              </tr>
            </thead>
            <tbody>
              {data.map((vuln, index) => (
                <tr
                  key={`${vuln.vulnerabilityId}-${vuln.cvssSeverity}`}
                  onClick={() => handleRowClick(vuln.vulnerabilityId)}
                  style={{ cursor: 'pointer' }}
                  title={`Click to view details for ${vuln.vulnerabilityId}`}
                >
                  <td className="align-middle">{index + 1}</td>
                  <td className="align-middle">
                    <CveLink cveId={vuln.vulnerabilityId} />
                  </td>
                  <td className="align-middle">
                    <span className={severityBadgeClass(vuln.cvssSeverity)}>
                      {vuln.cvssSeverity}
                    </span>
                  </td>
                  <td className="align-middle">
                    <span className="badge bg-light text-dark">
                      {vuln.occurrenceCount.toLocaleString()}
                    </span>
                  </td>
                  <td className="align-middle">
                    <span className="badge bg-light text-dark">
                      {vuln.affectedAssetCount.toLocaleString()}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <div className="card-footer text-muted small">
        <i className="bi bi-info-circle me-1"></i>
        Showing top 10 vulnerabilities ranked by total occurrences. Click any row for details.
      </div>

      {/* CVE Affected Systems Modal */}
      {showModal && (
        <div className="modal show d-block" tabIndex={-1} style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <div className="modal-dialog modal-lg modal-dialog-scrollable">
            <div className="modal-content">
              <div className="modal-header" style={{ backgroundColor: 'var(--scand-bg-header)', color: 'var(--scand-text-light)' }}>
                <h5 className="modal-title">
                  <i className="bi bi-server me-2"></i>
                  Affected Systems {modalData && `- ${modalData.cveId}`}
                </h5>
                <button type="button" className="btn-close btn-close-white" onClick={closeModal}></button>
              </div>
              <div className="modal-body">
                {modalLoading && (
                  <div className="text-center py-4">
                    <div className="spinner-border text-primary" role="status">
                      <span className="visually-hidden">Loading...</span>
                    </div>
                    <p className="mt-2 text-muted">Loading affected systems...</p>
                  </div>
                )}

                {modalError && (
                  <div className="alert alert-danger" role="alert">
                    <i className="bi bi-exclamation-triangle me-2"></i>
                    {modalError}
                  </div>
                )}

                {modalData && !modalLoading && (
                  <>
                    <div className="mb-3">
                      <span className={severityBadgeClass(modalData.severity)}>{modalData.severity}</span>
                      <span className="ms-2 text-muted">
                        {modalData.totalCount} system{modalData.totalCount !== 1 ? 's' : ''} affected
                        {domain && <span className="ms-1">(in domain: {domain})</span>}
                      </span>
                    </div>

                    {modalData.affectedAssets.length === 0 ? (
                      <p className="text-muted">No systems found for this vulnerability in your accessible scope.</p>
                    ) : (
                      <div className="table-responsive">
                        <table className="table table-sm table-hover mb-0">
                          <thead className="table-light">
                            <tr>
                              <th>System Name</th>
                              <th>IP Address</th>
                              <th>Domain</th>
                              <th>Type</th>
                            </tr>
                          </thead>
                          <tbody>
                            {modalData.affectedAssets.map((asset) => (
                              <tr key={asset.assetId}>
                                <td>
                                  <a href={`/assets/${asset.assetId}`} className="text-decoration-none">
                                    {asset.assetName}
                                  </a>
                                </td>
                                <td>{asset.assetIp || '-'}</td>
                                <td>{asset.adDomain || '-'}</td>
                                <td>{asset.assetType || '-'}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    )}

                    {modalData.totalCount >= 100 && (
                      <div className="alert alert-info mt-3 mb-0" role="alert">
                        <i className="bi bi-info-circle me-2"></i>
                        Showing first 100 affected systems. Use the asset overview for a complete list.
                      </div>
                    )}
                  </>
                )}
              </div>
              <div className="modal-footer">
                {modalData && modalData.affectedAssets.length > 0 && (
                  <button
                    type="button"
                    className="btn btn-outline-success me-auto"
                    onClick={handleExportAffectedSystems}
                    disabled={exporting}
                  >
                    {exporting ? (
                      <>
                        <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                        Exporting...
                      </>
                    ) : (
                      <>
                        <i className="bi bi-file-earmark-excel me-2"></i>
                        Export to Excel
                      </>
                    )}
                  </button>
                )}
                <button type="button" className="btn btn-secondary" onClick={closeModal}>Close</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * React component for displaying most vulnerable products table
 *
 * Displays top 10 products ranked by distinct vulnerability count.
 * Features:
 * - Bootstrap table with responsive design
 * - Critical/High severity counts with color coding
 * - Click handlers for drill-down navigation to product details
 * - Loading, error, and empty states
 * - Excel export for affected systems
 *
 * Feature: 036-vuln-stats-lense
 */

import React, { useEffect, useState } from 'react';
import ExcelJS from 'exceljs';
import { vulnerabilityStatisticsApi, type MostVulnerableProductDto, type AssetsByProductDto } from '../../services/api/vulnerabilityStatisticsApi';

/**
 * Props for MostVulnerableProducts component
 *
 * Feature: 059-vuln-stats-domain-filter
 * Task: T013 [US1]
 */
interface MostVulnerableProductsProps {
  /** Optional AD domain filter (null = all domains) */
  domain?: string | null;
  /** Optional AWS hosted filter (true = only cloud-hosted assets) */
  awsHosted?: boolean;
}

export default function MostVulnerableProducts({ domain, awsHosted }: MostVulnerableProductsProps = {}) {
  const [data, setData] = useState<MostVulnerableProductDto[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Modal state for product drilldown
  const [showModal, setShowModal] = useState<boolean>(false);
  const [modalLoading, setModalLoading] = useState<boolean>(false);
  const [modalData, setModalData] = useState<AssetsByProductDto | null>(null);
  const [modalError, setModalError] = useState<string | null>(null);

  // Export state
  const [exporting, setExporting] = useState<boolean>(false);

  /**
   * Handle row click - show systems with this product
   */
  const handleRowClick = async (product: string) => {
    setShowModal(true);
    setModalLoading(true);
    setModalError(null);
    setModalData(null);

    try {
      const result = await vulnerabilityStatisticsApi.getAssetsByProduct(product, domain, awsHosted);
      setModalData(result);
    } catch (err) {
      console.error('Error fetching assets with product:', err);
      setModalError('Failed to load systems. Please try again.');
    } finally {
      setModalLoading(false);
    }
  };

  const closeModal = () => {
    setShowModal(false);
    setModalData(null);
    setModalError(null);
  };

  /**
   * Export assets with product to Excel
   */
  const handleExportAssets = async () => {
    if (!modalData || modalData.assets.length === 0) return;

    setExporting(true);
    try {
      const workbook = new ExcelJS.Workbook();
      workbook.creator = 'Secman';
      workbook.created = new Date();

      const sheet = workbook.addWorksheet('Systems with Product');
      sheet.columns = [
        { header: 'System Name', key: 'name', width: 30 },
        { header: 'IP Address', key: 'ip', width: 18 },
        { header: 'Domain', key: 'domain', width: 20 },
        { header: 'Type', key: 'type', width: 15 },
        { header: 'Vulnerabilities', key: 'vulns', width: 15 },
      ];

      modalData.assets.forEach((asset) => {
        sheet.addRow({
          name: asset.assetName,
          ip: asset.assetIp || '-',
          domain: asset.adDomain || '-',
          type: asset.assetType || '-',
          vulns: asset.vulnerabilityCount,
        });
      });

      // Style header
      const headerRow = sheet.getRow(1);
      headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
      headerRow.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF3D4F4F' } };
      headerRow.height = 22;

      // Generate and download
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
      });

      const safeProduct = modalData.product.replace(/[^a-zA-Z0-9-]/g, '_').substring(0, 50);
      const dateStr = new Date().toISOString().split('T')[0];
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `Systems_${safeProduct}_${dateStr}.xlsx`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      console.error('Export failed:', err);
    } finally {
      setExporting(false);
    }
  };

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);
        const result = await vulnerabilityStatisticsApi.getMostVulnerableProducts(domain, awsHosted);
        setData(result);
      } catch (err) {
        console.error('Error fetching most vulnerable products:', err);
        setError('Failed to load product statistics. Please try again later.');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [domain, awsHosted]); // Re-fetch when domain or awsHosted changes

  // Loading state
  if (loading) {
    return (
      <div className="card">
        <div className="card-body text-center py-5">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
          <p className="mt-3 text-muted">Loading product statistics...</p>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="card">
        <div className="card-body">
          <div className="alert alert-danger" role="alert">
            <i className="bi bi-exclamation-triangle me-2"></i>
            {error}
          </div>
        </div>
      </div>
